mapper.select:
SELECT id, record_date AS recordDate, product_id AS productId, product_name AS productName,
       volume, open_interest AS openInterest, oi_change AS oiChange
FROM shfe_trade_daily
WHERE YEAR(record_date) = #{year} AND MONTH(record_date) = #{month}
  AND product_id = #{productId}
ORDER BY record_date ASC
